PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?title ?type WHERE {
  ?courses_assignments a :Courses_Assignments .
  ?assignments a :Assignments .
  ?courses_assignments p:hasAssignments ?assignments .
  ?courses a :Courses .
  ?courses_assignments p:hasCourses ?courses .
  ?courses p:title ?title .
  ?assignments p:type ?type .
} }
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasAssignments ?child ; p:hasCourses ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Courses } }
  FILTER(?nf = ?total)
} }
}

